// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Helper: Get priority badge variant
const getPriorityVariant = (priority?: string): 'default' | 'success' | 'warning' | 'error' => {
  if (priority === 'low') return 'success';
  if (priority === 'medium') return 'warning';
  if (priority === 'high') return 'error';
  return 'default';
};

// Helper: Get priority label
const getPriorityLabel = (priority?: string): string => {
  return priority ? priority.charAt(0).toUpperCase() + priority.slice(1) : 'None';
};

// Helper: Get initials from name
const getInitials = (name?: string): string => {
  if (!name) return '?';
  return name.split(' ').map(word => word.charAt(0)).join('').toUpperCase().slice(0, 2);
};

// TaskCard sub-component
function TaskCard({
  task,
  allColumns,
  onEdit,
  onMove,
}: {
  task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string };
  allColumns: Array<{ id?: string; name?: string }>;
  onEdit: (task: typeof task) => void;
  onMove: (taskId: string, toColumn: string) => void;
}) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');
  const [showMoveMenu, setShowMoveMenu] = useState(false);

  const handleDoubleClick = () => {
    setIsEditing(true);
    setEditTitle(task.title || '');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      setIsEditing(true);
      setEditTitle(task.title || '');
    }
  };

  const handleSaveEdit = () => {
    onEdit({ ...task, title: editTitle });
    setIsEditing(false);
  };

  const handleEditCancel = () => {
    setIsEditing(false);
  };

  const handleMenuKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Escape') {
      setShowMoveMenu(false);
    }
  };

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        {isEditing ? (
          <Stack gap="var(--ggui-spacing-2)">
            <Input
              label="Task title"
              value={editTitle}
              onChange={setEditTitle}
              placeholder="Enter task title"
              size="sm"
            />
            <Row gap="var(--ggui-spacing-2)" justify="end">
              <Button variant="ghost" size="sm" onClick={handleEditCancel}>
                Cancel
              </Button>
              <Button variant="primary" size="sm" onClick={handleSaveEdit}>
                Save
              </Button>
            </Row>
          </Stack>
        ) : (
          <>
            <Text
              as={Clickable}
              onClick={handleDoubleClick}
              onKeyDown={handleKeyDown}
              variant="body"
              weight="semibold"
              truncate
              title="Double-click or press Enter to edit"
              aria-label="Task title: double-click or press Enter to edit"
            >
              {task.title || 'Untitled Task'}
            </Text>
            <Row gap="var(--ggui-spacing-1)" align="center" justify="between">
              <Row gap="var(--ggui-spacing-1)" align="center">
                <Badge variant={getPriorityVariant(task.priority)} size="sm">
                  {getPriorityLabel(task.priority)}
                </Badge>
                {task.assignee && (
                  <Avatar name={task.assignee} size="xs" shape="circle" />
                )}
              </Row>
              <Button
                variant="ghost"
                size="xs"
                onClick={() => setShowMoveMenu(!showMoveMenu)}
                aria-label="Move task to another column"
                aria-expanded={showMoveMenu}
              >
                <Icon name="arrow-right" size={14} />
              </Button>
            </Row>
            {task.dueDate && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                Due: {new Date(task.dueDate).toLocaleDateString()}
              </Text>
            )}
            {showMoveMenu && allColumns.length > 0 && (
              <Box
                padding="var(--ggui-spacing-2)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-md)"
                role="menu"
                onKeyDown={handleMenuKeyDown}
                style={{ marginTop: 'var(--ggui-spacing-2)' }}
              >
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                    Move to:
                  </Text>
                  {allColumns.map((col, idx) => (
                    <Button
                      key={col.id}
                      role="menuitem"
                      variant="ghost"
                      size="xs"
                      onClick={() => {
                        onMove(task.id || '', col.id || '');
                        setShowMoveMenu(false);
                      }}
                      onKeyDown={(e) => {
                        if (e.key === 'Escape') {
                          setShowMoveMenu(false);
                        }
                      }}
                    >
                      {col.name}
                    </Button>
                  ))}
                </Stack>
              </Box>
            )}
          </>
        )}
      </Stack>
    </Card>
  );
}

// Column sub-component
function KanbanColumn({
  column,
  tasks,
  allColumns,
  onTaskEdit,
  onTaskMove,
  onAddTask,
}: {
  column: { id?: string; name?: string };
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  allColumns: Array<{ id?: string; name?: string }>;
  onTaskEdit: (task: any) => void;
  onTaskMove: (taskId: string, toColumn: string) => void;
  onAddTask: (columnId: string, title: string, priority: string) => void;
}) {
  const [isAddingTask, setIsAddingTask] = useState(false);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('medium');

  const handleAddTask = () => {
    if (newTaskTitle.trim()) {
      onAddTask(column.id || '', newTaskTitle, newTaskPriority);
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setIsAddingTask(false);
    }
  };

  return (
    <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
      <Stack gap="var(--ggui-spacing-3)">
        <Row align="center" justify="between">
          <Heading level={3}>{column.name}</Heading>
          <Badge variant="secondary" size="sm">
            {tasks.length}
          </Badge>
        </Row>
        <Divider margin="var(--ggui-spacing-2)" orientation="horizontal" />
        <Stack gap="var(--ggui-spacing-2)">
          {tasks.map(task => (
            <TaskCard
              key={task.id}
              task={task}
              allColumns={allColumns}
              onEdit={onTaskEdit}
              onMove={onTaskMove}
            />
          ))}
        </Stack>
        {isAddingTask ? (
           <Card padding="var(--ggui-spacing-2)" background="var(--ggui-color-primary-50)" radius="md">
            <Stack gap="var(--ggui-spacing-2)">
              <Input
                label="Task title"
                value={newTaskTitle}
                onChange={setNewTaskTitle}
                placeholder="Enter task title"
                size="sm"
              />
              <Select
                label="Priority"
                value={newTaskPriority}
                onChange={setNewTaskPriority}
                options={[
                  { value: 'low', label: 'Low' },
                  { value: 'medium', label: 'Medium' },
                  { value: 'high', label: 'High' },
                ]}
                size="sm"
              />
              <Row gap="var(--ggui-spacing-2)" justify="end">
                <Button variant="ghost" size="sm" onClick={() => { setIsAddingTask(false); setNewTaskTitle(''); }}>
                  Cancel
                </Button>
                <Button variant="primary" size="sm" onClick={handleAddTask}>
                  Create
                </Button>
              </Row>
            </Stack>
          </Box>
        ) : (
           <Button
             variant="outline"
             size="sm"
             fullWidth
             onClick={() => setIsAddingTask(true)}
             aria-label="Add new task to this column"
           >
             + Add Task
           </Button>
        )}
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // State
  const [localTasks, setLocalTasks] = useState(props.tasks || []);

  // Sync with incoming stream updates
  useEffect(() => {
    if (taskChanged.latest?.task) {
      const updatedTask = taskChanged.latest.task;
      setLocalTasks(prev => {
        const taskIndex = prev.findIndex(t => t.id === updatedTask.id);
        if (taskIndex >= 0) {
          const newTasks = [...prev];
          newTasks[taskIndex] = { ...newTasks[taskIndex], ...updatedTask };
          return newTasks;
        } else if (taskChanged.latest?.action === 'create') {
          return [...prev, updatedTask];
        }
        return prev;
      });
    }
  }, [taskChanged.latest]);

  // Handlers
  const handleTaskEdit = useCallback((updatedTask: any) => {
    setLocalTasks(prev => prev.map(t => (t.id === updatedTask.id ? updatedTask : t)));
    taskUpdate({ action: 'edit', taskId: updatedTask.id || '', data: { column: updatedTask.column || '' } });
  }, [taskUpdate]);

  const handleTaskMove = useCallback((taskId: string, toColumn: string) => {
    setLocalTasks(prev =>
      prev.map(t => (t.id === taskId ? { ...t, column: toColumn } : t))
    );
    taskUpdate({ action: 'move', taskId, data: { column: toColumn } });
  }, [taskUpdate]);

  const handleAddTask = useCallback((columnId: string, title: string, priority: string) => {
    const newTaskId = `task-${Date.now()}`;
    const newTask = {
      id: newTaskId,
      title,
      priority: priority as 'low' | 'medium' | 'high',
      column: columnId,
      assignee: '',
      dueDate: '',
    };
    setLocalTasks(prev => [...prev, newTask]);
    taskUpdate({ action: 'create', taskId: newTaskId, data: { column: columnId } });
  }, [taskUpdate]);

  // Computed values
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof localTasks> = {};
    props.columns.forEach(col => {
      grouped[col.id || ''] = localTasks.filter(t => t.column === col.id);
    });
    return grouped;
  }, [localTasks, props.columns]);

  const totalTasks = localTasks.length;
  const completedTasks = localTasks.filter(t => t.column === 'done').length;

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
          <Row gap="var(--ggui-spacing-4)" align="center" justify="between">
            <Heading level={2}>Task Board</Heading>
            <Row gap="var(--ggui-spacing-4)" align="center">
              <Box>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" size="sm">
                  Total Tasks
                </Text>
                <Text variant="label" size="lg" color="var(--ggui-color-primary-600)" weight="bold">
                  {totalTasks}
                </Text>
              </Box>
              <Divider orientation="vertical" margin="var(--ggui-spacing-2)" color="var(--ggui-color-outline)" />
              <Box>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" size="sm">
                  Completed
                </Text>
                <Text variant="label" size="lg" color="var(--ggui-color-success-600)" weight="bold">
                  {completedTasks}
                </Text>
              </Box>
              <Divider orientation="vertical" margin="var(--ggui-spacing-2)" color="var(--ggui-color-outline)" />
              <Progress
                value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0}
                variant="success"
                size="md"
                showLabel={false}
              />
            </Row>
          </Row>
        </Card>

        {/* Kanban Columns */}
        <Row gap="var(--ggui-spacing-4)" align="stretch" wrap={true}>
          {props.columns.map(column => (
            <KanbanColumn
              key={column.id}
              column={column}
              tasks={tasksByColumn[column.id || ''] || []}
              allColumns={props.columns}
              onTaskEdit={handleTaskEdit}
              onTaskMove={handleTaskMove}
              onAddTask={handleAddTask}
            />
          ))}
        </Row>
      </Stack>
    </Container>
  );
}
